284→function buildWindowObjects(wallContexts) {
285→  return wallContexts
286→    .flatMap((context) => context.openings)
287→    .filter((opening) => opening.kind === 'window')
288→    .map((opening) => {
289→      const desc = createOpeningInsertDescriptor(opening);
290→      desc.geometry = 'window';
291→      desc.windowType = opening.type || 'standard';
292→      desc.openDirection = opening.openDirection || 'left';
293→      return desc;
294→    });
295→}
296→
297→function buildStairObjects(floor, floorLevel, landings, landingElevationMap) {
298→  return (floor.stairs || [])
299→    .map((stair) => createStairDescriptor(stair, floorLevel, floor.id, landings, landingElevationMap))
300→    .filter(Boolean);
301→}
302→
303→function buildLandingObjects(floor, floorLevel, landingElevationMap) {
304→  return (floor.landings || []).map((landing) => createBoxDescriptor(
305→    landing.id,
306→    'landing',
307→    { x: landing.position.x, y: landing.position.y },
308→    {
309→      x: landing.width,
310→      y: landing.thickness ?? 200,
311→      z: landing.depth,
312→    },
313→    floorLevel + (landingElevationMap.get(landing.id) || 0),
314→    (landing.rotation || 0) * Math.PI / 180,
315→    {
316→      sourceId: landing.id,
317→      floorId: floor.id,
318→    }
319→  ));
320→}
321→
322→function buildFixtureObjects(floor, floorLevel) {
323→  // Sit fixtures on top of the highest slab surface (or floorLevel if no slabs)
324→  // +1mm offset prevents z-fighting where fixture bottom meets slab top
325→  const slabs = floor.slabs || [];
326→  const slabTop = slabs.length > 0
327→    ? Math.max(...slabs.map(s => s.elevation ?? floorLevel))
328→    : floorLevel;
329→  const fixtureBase = Math.max(slabTop, floorLevel) + 1;
330→
331→  return (floor.fixtures || []).map((fixture) => {
332→    const descriptor = createBoxDescriptor(
333→      fixture.id,
334→      'fixture',
335→      { x: fixture.x, y: fixture.y },
336→      {
337→        x: fixture.width,
338→        y: FIXTURE_3D_HEIGHTS[fixture.fixtureType] || 750,
339→        z: fixture.depth,
340→      },
341→      fixtureBase,
342→      (fixture.rotation || 0) * Math.PI / 180,
343→      {
344→        sourceId: fixture.id,
345→        floorId: floor.id,
346→        materialKey: 'fixture_' + fixture.fixtureType,
347→      }
348→    );
349→    descriptor.geometry = 'fixture';
350→    descriptor.fixtureType = fixture.fixtureType;
351→    return descriptor;
352→  });
353→}
354→
355→export function buildFloorPreviewObjects(floor) {
356→  const floorLevel = getFloorElevation(floor);
357→  const landings = floor.landings || [];
358→  const stairs = floor.stairs || [];
359→
360→  const landingElevationMap = new Map(
361→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorLevel)])
362→  );
363→
364→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
365→
366→  return [
367→    ...buildSlabObjects(floor),
368→    ...buildWallObjects(wallContexts),
369→    ...buildColumnObjects(floor, floorLevel),
370→    ...buildBeamObjects(floor),
371→    ...buildStairObjects(floor, floorLevel, landings, landingElevationMap),
372→    ...buildLandingObjects(floor, floorLevel, landingElevationMap),
373→    ...buildDoorObjects(wallContexts),
374→    ...buildWindowObjects(wallContexts),
375→    ...buildFixtureObjects(floor, floorLevel),
376→  ];
377→}
