468→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
469→  const root = new THREE.Group();
470→  root.name = 'preview-root';
471→
472→  for (const floor of sceneDescriptor.floors) {
473→    const floorGroup = new THREE.Group();
474→    floorGroup.name = `floor-${floor.floorId}`;
475→    floorGroup.visible = floor.visible;
476→    floorGroup.userData = {
477→      floorId: floor.floorId,
478→      floorName: floor.name,
479→      elevation: floor.elevation,
