const FIXTURE_BUILDERS = {
  kitchenTop: buildKitchenTopFixture,
  toilet: buildToiletFixture,
  lavatory: buildLavatoryFixture,
  table: buildTableFixture,
  tv: buildTvFixture,
  sofa: buildSofaFixture,
  bed: buildBedFixture,
};

function createFixtureObject(descriptor, materialPalette, isSelected) {
  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
  if (!builder) {
    return createBoxObject(descriptor, materialPalette, isSelected);
  }

  const group = new THREE.Group();
  const W = descriptor.size.x;
  const H = descriptor.size.y;
  const D = descriptor.size.z;

  builder(group, W, H, D, materialPalette, isSelected);

  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);

  return group;
}

// ── Dispatcher ──

function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
  if (descriptor.geometry === 'prism') {
    return createPrismObject(descriptor, materialPalette, isSelected);
  }

  if (descriptor.geometry === 'stair') {
    return createStairObject(descriptor, materialPalette, isSelected);
  }

  if (descriptor.geometry === 'window') {
    return createWindowObject(descriptor, materialPalette, isSelected);
  }

  if (descriptor.geometry === 'railing') {
    return createRailingObject(descriptor, materialPalette, isSelected);
  }

  if (descriptor.geometry === 'fixture') {
    return createFixtureObject(descriptor, materialPalette, isSelected);
  }

  return createBoxObject(descriptor, materialPalette, isSelected);
}

function matchesSelection(descriptor, selection) {
  if (!selection?.selectedId || selection.selectedType !== descriptor.kind) return false;
  return (descriptor.metadata?.sourceId || descriptor.id) === selection.selectedId;
}

function assignPreviewMetadata(object, descriptor, floor) {
  const previewTarget = {
    kind: descriptor.kind,
    sourceId: descriptor.metadata?.sourceId || descriptor.id,
    floorId: descriptor.metadata?.floorId || floor.floorId,
  };

  object.traverse((node) => {
    node.userData = {
      ...node.userData,
      previewTarget,
    };
  });
}

export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
  const root = new THREE.Group();
  root.name = 'preview-root';

  for (const floor of sceneDescriptor.floors) {
    const floorGroup = new THREE.Group();
    floorGroup.name = `floor-${floor.floorId}`;
    floorGroup.visible = floor.visible;
    floorGroup.userData = {
      floorId: floor.floorId,
      floorName: floor.name,
      elevation: floor.elevation,
    };

    for (const descriptor of floor.objects) {
      const isSelected = matchesSelection(descriptor, selection);
      const object = createObjectForDescriptor(descriptor, materialPalette, isSelected);
      object.name = descriptor.id;
      object.userData = {
        id: descriptor.id,
        kind: descriptor.kind,
        metadata: descriptor.metadata,
      };
      assignPreviewMetadata(object, descriptor, floor);
      floorGroup.add(object);
    }

    root.add(floorGroup);
  }

  return root;
}

import { formatMeasurement } from '@/annotations/format';
import { getBeamDisplayLabel } from '@/domain/beamLabels';
import { getColumnListLabel } from '@/domain/columnLabels';
import { getLandingDisplayLabel } from '@/domain/landingLabels';
import { getSlabDisplayLabel } from '@/domain/slabLabels';
import { getStairDisplayLabel } from '@/domain/stairLabels';
import { beamLength } from '@/geometry/beamGeometry';
import { slabArea } from '@/geometry/slabGeometry';
import { stairRun, stairTotalRise } from '@/geometry/stairGeometry';
import { wallLength } from '@/geometry/wallGeometry';

const INSPECTABLE_TYPES = new Set([
  'wall',
  'beam',
  'column',
  'slab',
  'stair',
  'landing',
  'door',
  'window',
  'fixture',
]);

const TYPE_LABELS = {
  wall: 'Wall',
  beam: 'Beam',
  column: 'Column',
  slab: 'Slab',
  stair: 'Stair',
  landing: 'Landing',
  door: 'Door',
  window: 'Window',
  fixture: 'Fixture',
};

const FIXTURE_TYPE_LABELS = {
  kitchenTop: 'Kitchen Top',
  toilet: 'Toilet',
  lavatory: 'Lavatory',
  table: 'Table',
  tv: 'TV',
  sofa: 'Sofa',
};

function mmRow(label, value) {
  return { label, value: formatMeasurement(value || 0) };
}

function areaRow(label, value) {
  return { label, value: `${(Math.abs(value || 0) / 1_000_000).toFixed(2)} m²` };
}

function findObjectInFloor(floor, selectedType, selectedId) {
  switch (selectedType) {
    case 'wall':
      return floor.walls?.find((wall) => wall.id === selectedId) || null;
    case 'beam':
      return (floor.beams || []).find((beam) => beam.id === selectedId) || null;
    case 'column':
      return (floor.columns || []).find((column) => column.id === selectedId) || null;
    case 'slab':
      return (floor.slabs || []).find((slab) => slab.id === selectedId) || null;
    case 'stair':
      return (floor.stairs || []).find((stair) => stair.id === selectedId) || null;
    case 'landing':
      return (floor.landings || []).find((landing) => landing.id === selectedId) || null;
    case 'door':
      return floor.doors?.find((door) => door.id === selectedId) || null;
    case 'window':
      return floor.windows?.find((windowItem) => windowItem.id === selectedId) || null;
    case 'fixture':
      return (floor.fixtures || []).find((fixture) => fixture.id === selectedId) || null;
    default:
      return null;
  }
}

function titleForObject(selectedType, object, floor) {
  switch (selectedType) {
    case 'beam':
      return getBeamDisplayLabel(object, floor.columns || []);
    case 'column':
      return getColumnListLabel(object, floor.columns || []);
    case 'slab':
      return getSlabDisplayLabel(object);
    case 'stair':
      return getStairDisplayLabel(object);
    case 'landing':
      return getLandingDisplayLabel(object);
    case 'wall':
    case 'door':
    case 'window':
      return `${TYPE_LABELS[selectedType]} ${object.id.split('_').pop()}`;
    case 'fixture':
      return FIXTURE_TYPE_LABELS[object.fixtureType] || 'Fixture';
    default:
      return object?.id || TYPE_LABELS[selectedType] || 'Object';
  }
}

function rowsForObject(selectedType, object, floor) {
  switch (selectedType) {
    case 'wall':
      return [
        mmRow('Length', wallLength(object)),
        mmRow('Thickness', object.thickness),
        mmRow('Height', object.height),
      ];
    case 'beam':
      return [
        mmRow('Span', beamLength(object, floor.columns || [])),
        mmRow('Width', object.width),
        mmRow('Depth', object.depth),
      ];
    case 'column':
      return [
        mmRow('Width', object.width),
        mmRow('Depth', object.depth),
        mmRow('Height', object.height),
      ];
    case 'slab':
      return [
        mmRow('Thickness', object.thickness),
